const Dev = "ASSET_ID_START_MET_36 "  // <-- jouw asset ID invullen

// ─── ID mapping (zelfde als Eastron) ────────────────────────────────────────
// LHI110 msg type 2 levert: import, export, L1/L2/L3 voltage + current
const CHANNELS = [
    { key: "activeImportReading", id: 4600, scale: false },  // kWh import
    { key: "activeExportReading", id: 4500, scale: false },  // kWh export
    { key: "l1VoltageAver_mV",   id: 3000, scale: true  },  // mV → V  (/1000)
    { key: "l2VoltageAver_mV",   id: 3100, scale: true  },  // mV → V
    { key: "l3VoltageAver_mV",   id: 3200, scale: true  },  // mV → V
    { key: "l1CurrentPeak_mA",   id: 3300, scale: true  },  // mA → A  (/1000)
    { key: "l2CurrentPeak_mA",   id: 3400, scale: true  },  // mA → A
    { key: "l3CurrentPeak_mA",   id: 3500, scale: true  },  // mA → A
]

// ─── Helpers ─────────────────────────────────────────────────────────────────
function toHexString(byteArray) {
    return Array.prototype.map.call(byteArray, function(byte) {
        return ('0' + (byte & 0xFF).toString(16)).slice(-2);
    }).join('-');
}

function zfill(num, len) {
    return (Array(len).join("0") + num).slice(-len);
}

function arrToUint16(b, i) {
    return (b[i] << 8 | b[i + 1]);
}

function arrToUint32(b, i) {
    return (b[i] << 24 | b[i + 1] << 16 | b[i + 2] << 8 | b[i + 3]);
}

function arrToUint40(b, i) {
    // 40-bit: JS bitshift werkt op 32-bit, dus hoge byte apart behandelen
    return (b[i] * 0x100000000) + (b[i+1] << 24 | b[i+2] << 16 | b[i+3] << 8 | b[i+4]);
}

function decodePower(pwrData) {
    if ((1 << 15) & pwrData) {
        return (pwrData & ~(1 << 15)) * 100;
    }
    return pwrData;
}

function decodeVoltages(b, i) {
    var lineVoltArr = arrToUint32(b, i);
    var l1 = ((lineVoltArr & 0x3FF00000) >> 20) * 250;
    var l2 = ((lineVoltArr & 0x000FFC00) >> 10) * 250;
    var l3 = ((lineVoltArr & 0x000003FF) >>  0) * 250;
    if (l1 !== 0) l1 += 20000;
    if (l2 !== 0) l2 += 20000;
    if (l3 !== 0) l3 += 20000;
    return [l1, l2, l3];
}

function decodeCurrents(b, i) {
    var lineCurrArr = arrToUint32(b, i);
    return [
        ((lineCurrArr & 0x3FF00000) >> 20) * 100,
        ((lineCurrArr & 0x000FFC00) >> 10) * 100,
        ((lineCurrArr & 0x000003FF) >>  0) * 100
    ];
}

// ─── Payload inlezen ─────────────────────────────────────────────────────────
var buf = (typeof msg.payload === "string")
    ? Buffer.from(msg.payload, "base64")
    : msg.payload

if (!Buffer.isBuffer(buf) || buf.length < 5) {
    node.error("LHI110: ongeldige payload - te kort", msg);
    return null;
}

var bytes = Array.from(buf);

// fPort 2 verwacht: byte[0] = msgType, byte[1..4] = timestamp
var msgType = bytes[0];

if (msgType !== 0x02) {
    node.warn("LHI110: verwacht msg type 2, ontvangen: " + msgType);
    return null;
}

// ─── Timestamp ───────────────────────────────────────────────────────────────
var ts = msg.time ? new Date(msg.time).toISOString() : new Date().toISOString();

// ─── Msg type 2 decoderen ────────────────────────────────────────────────────
// Byte layout type 2:
//  [0]      msgType
//  [1..4]   timestamp (uint32)
//  [5..9]   activeImportReading (uint40, Wh)
//  [10..14] activeExportReading (uint40, Wh)
//  [15..16] actL1ImportPowerPeak
//  [17..18] actL1ImportPowerAver
//  [19..20] actL2ImportPowerPeak
//  [21..22] actL2ImportPowerAver
//  [23..24] actL3ImportPowerPeak
//  [25..26] actL3ImportPowerAver
//  [27..28] actL1ExportPowerAver
//  [29..30] actL2ExportPowerAver
//  [31..32] actL3ExportPowerAver
//  [33..36] voltages (packed uint32)
//  [37..40] currents (packed uint32)

var raw = {};
raw.activeImportReading = arrToUint40(bytes, 5)  / 1000;  // Wh → kWh
raw.activeExportReading = arrToUint40(bytes, 10) / 1000;  // Wh → kWh

var volts    = decodeVoltages(bytes, 33);
var currents = decodeCurrents(bytes, 37);

raw.l1VoltageAver_mV = volts[0];
raw.l2VoltageAver_mV = volts[1];
raw.l3VoltageAver_mV = volts[2];
raw.l1CurrentPeak_mA = currents[0];
raw.l2CurrentPeak_mA = currents[1];
raw.l3CurrentPeak_mA = currents[2];

// ─── MD array opbouwen ───────────────────────────────────────────────────────
var md = [];

for (var i = 0; i < CHANNELS.length; i++) {
    var ch = CHANNELS[i];
    var val = raw[ch.key];
    if (val == null || !isFinite(val)) continue;
    if (ch.scale) val = Math.round((val / 1000) * 1000) / 1000;  // mV/mA → V/A
    else          val = Math.round(val * 1000) / 1000;
    md.push({ Id: ch.id, Val: val });
}

// LoRaWAN signaalwaarden meesturen
if (msg.snr  !== undefined) md.push({ Id: 5400, Val: parseFloat(msg.snr) });
if (msg.rssi !== undefined) md.push({ Id: 5500, Val: parseFloat(msg.rssi) });
if (msg.dr?.spreadFactor !== undefined)
    md.push({ Id: 5200, Val: parseFloat(msg.dr.spreadFactor) });

// ─── Output opbouwen ─────────────────────────────────────────────────────────
var mid = global.get("mid") || 0;

if (md.length === 0) {
    node.warn("LHI110: geen geldige meetwaarden in payload");
    return null;
}

msg.payload = {
    MID: mid,
    D: [{
        Dev: Dev,
        ED:  [],
        MD:  md,
        TS:  ts
    }]
};

global.set("mid", mid + 1);
return msg;
